import 'dart:async';\nimport 'dart:ffi';\nimport 'dart:io';\nimport 'dart:isolate';\nimport 'dart:typed_data';\nimport 'package:ffi/ffi.dart';\nimport 'package:flutter/material.dart';\nimport 'package:flutter_webrtc/flutter_webrtc.dart';\n\n// --- FFI Setup ---\ntypedef _InitPipelineC = IntPtr Function();\ntypedef _InitPipelineDart = int Function();\n\ntypedef _ProcessFrameC = Pointer<Utf8> Function(IntPtr context, Pointer<Uint8> frameData, Int32 width, Int32 height);\ntypedef _ProcessFrameDart = Pointer<Utf8> Function(int context, Pointer<Uint8> frameData, int width, int height);\n\ntypedef _ReleasePipelineC = Void Function(IntPtr context);\ntypedef _ReleasePipelineDart = void Function(int context);\n\nclass SlrNative {\n  static late final DynamicLibrary _lib;\n  static late final _InitPipelineDart _initPipeline;\n  static late final _ProcessFrameDart _processFrame;\n  static late final _ReleasePipelineDart _releasePipeline;\n\n  static void initialize() {\n    if (Platform.isAndroid || Platform.isLinux) {\n      _lib = DynamicLibrary.open('libslr_input_kit.so');\n    } else if (Platform.isWindows) {\n      _lib = DynamicLibrary.open('slr_input_kit.dll');\n    } else if (Platform.isIOS || Platform.isMacOS) {\n      _lib = DynamicLibrary.executable();\n    } else {\n      throw UnsupportedError('Unknown platform: ${Platform.operatingSystem}');\n    }\n\n    _initPipeline = _lib.lookupFunction<_InitPipelineC, _InitPipelineDart>('init_slr_pipeline');\n    _processFrame = _lib.lookupFunction<_ProcessFrameC, _ProcessFrameDart>('process_video_frame');\n    _releasePipeline = _lib.lookupFunction<_ReleasePipelineC, _ReleasePipelineDart>('release_slr_pipeline');\n  }\n\n  static int init() => _initPipeline();\n  static void release(int context) => _releasePipeline(context);\n\n  static String processFrame(int context, Uint8List frameData, int width, int height) {\n    final Pointer<Uint8> pData = malloc.allocate<Uint8>(frameData.length);\n    pData.asTypedList(frameData.length).setAll(0, frameData);\n\n    final Pointer<Utf8> resultPtr = _processFrame(context, pData, width, height);\n    final String result = resultPtr.toDartString();\n\n    malloc.free(pData);\n    return result;\n  }\n}\n\n// --- Flutter Widget ---\nclass SlrInputWidget extends StatefulWidget {\n  final Function(String) onSignRecognized;\n\n  const SlrInputWidget({Key? key, required this.onSignRecognized}) : super(key: key);\n\n  @override\n  State<SlrInputWidget> createState() => _SlrInputWidgetState();\n}\n\nclass _SlrInputWidgetState extends State<SlrInputWidget> {\n  RTCVideoRenderer _localRenderer = RTCVideoRenderer();\n  MediaStream? _localStream;\n  bool _isProcessing = false;\n  int? _pipelineContext;\n  String _currentText = "";\n\n  @override\n  void initState() {\n    super.initState();\n    initRenderers();\n    SlrNative.initialize();\n    _pipelineContext = SlrNative.init();\n  }\n\n  @override\n  void dispose() {\n    if (_pipelineContext != null) SlrNative.release(_pipelineContext!);\n    _localStream?.dispose();\n    _localRenderer.dispose();\n    super.dispose();\n  }\n\n  Future<void> initRenderers() async {\n    await _localRenderer.initialize();\n    final Map<String, dynamic> mediaConstraints = {\n      'audio': false,\n      'video': {'facingMode': 'user'}\n    };\n    try {\n      _localStream = await navigator.mediaDevices.getUserMedia(mediaConstraints);\n      _localRenderer.srcObject = _localStream;\n      \n      // Mocking frame processing loop\n      Timer.periodic(const Duration(milliseconds: 500), (timer) {\n         _processCameraFrame();\n      });\n    } catch (e) {\n      print(e.toString());\n    }\n    setState(() {});\n  }\n\n  Future<void> _processCameraFrame() async {\n    if (_isProcessing || _pipelineContext == null) return;\n    _isProcessing = true;\n\n    // 1. In a real app we would use WebRTC's VideoTrack/Frame APIs or Camera plugin\n    // to extract the raw RGBA/YUV frame buffer.\n    // Here we simulate it with a dummy buffer.\n    Uint8List dummyFrame = Uint8List(640 * 480 * 4);\n    \n    // 2. Offload to native isolate\n    // Real app: compute(_runNativeInference, dummyFrame)\n    String text = SlrNative.processFrame(_pipelineContext!, dummyFrame, 640, 480);\n    \n    if (text != _currentText) {\n      setState(() { _currentText = text; });\n      widget.onSignRecognized(text);\n    }\n\n    _isProcessing = false;\n  }\n\n  @override\n  Widget build(BuildContext context) {\n    return Stack(\n      children: [\n        RTCVideoView(_localRenderer, mirror: true),\n        Positioned(\n          bottom: 20,\n          left: 20,\n          right: 20,\n          child: Container(\n            padding: const EdgeInsets.all(12),\n            decoration: BoxDecoration(\n              color: Colors.black54,\n              borderRadius: BorderRadius.circular(8),\n            ),\n            child: Text(\n              _currentText.isEmpty ? "수어를 시작해주세요..." : _currentText,\n              style: const TextStyle(color: Colors.white, fontSize: 24, fontWeight: FontWeight.bold),\n              textAlign: TextAlign.center,\n            ),\n          ),\n        ),\n      ],\n    );\n  }\n}\n
